class Solution {
public:
    int countVowelPermutation(int n) {
        const int MOD = 1e9 + 7;
        vector<int> dp(5, 1);
        vector<vector<int>> graph = {{1, 2}, {0, 2, 3}, {0, 3}, {1, 3}, {0}};
        for (int i = 1; i < n; i++) {
            vector<int> ndp(5);
            for (int j = 0; j < 5; j++) {
                for (int k : graph[j]) {
                    ndp[k] = (ndp[k] + dp[j]) % MOD;
                }
            }
            dp = ndp;
        }
        int res = 0;
        for (int i : dp) res = (res + i) % MOD;
        return res;
    }
};
